'use client';

import { useState } from 'react';
import { NodeViewWrapper, type NodeViewProps } from '@tiptap/react';
import { Code02 } from '@/icons';
import { cx } from '@/utils/cx';
import { HtmlEmbedDialog } from './HtmlEmbedDialog';

export function HtmlEmbedNodeView({
  node,
  updateAttributes,
  deleteNode,
  selected,
  editor,
}: NodeViewProps) {
  const [isOpen, setIsOpen] = useState(false);
  const html = (node.attrs.html ?? '') as string;

  const isEditable = editor?.isEditable ?? true;

  return (
    <NodeViewWrapper
      as="div"
      data-html-embed-wrapper=""
      className={cx(
        'group relative my-3 rounded-lg border border-dashed border-secondary bg-primary_subtle px-3 py-2',
        selected && 'ring-2 ring-brand',
      )}
    >
      {isEditable && (
        <div
          className="absolute right-2 top-2 z-1 flex gap-1 opacity-0 transition group-hover:opacity-100 focus-within:opacity-100"
          contentEditable={false}
        >
          <button
            type="button"
            onClick={() => setIsOpen(true)}
            className="flex items-center gap-1 rounded-md bg-primary px-2 py-1 text-xs font-medium text-secondary shadow-xs ring-1 ring-secondary_alt hover:bg-primary_hover"
          >
            <Code02 className="size-3.5" />
            Edit HTML
          </button>
          <button
            type="button"
            onClick={() => deleteNode()}
            className="rounded-md bg-primary px-2 py-1 text-xs font-medium text-error-primary shadow-xs ring-1 ring-secondary_alt hover:bg-primary_hover"
          >
            Remove
          </button>
        </div>
      )}

      {html ? (
        <pre
          contentEditable={false}
          className="my-1 max-h-80 overflow-auto rounded-md bg-secondary px-3 py-2 pr-24 font-mono text-xs whitespace-pre-wrap break-all text-tertiary"
        >
          {html}
        </pre>
      ) : (
        <div
          contentEditable={false}
          className="flex items-center gap-2 py-2 text-sm text-tertiary"
        >
          <Code02 className="size-4" />
          Empty HTML embed — click &quot;Edit HTML&quot; to add markup.
        </div>
      )}

      <HtmlEmbedDialog
        isOpen={isOpen}
        initialHtml={html}
        onClose={() => setIsOpen(false)}
        onSave={(next) => updateAttributes({ html: next })}
      />
    </NodeViewWrapper>
  );
}
